function reverseString(str) {
  let reversed = '';
  for (let i = str.length - 1; i >= 0; i--) {
    reversed += str[i];
  }
  return reversed;
}

// Alternative:
function reverseStringRecursive(str, index = str.length - 1) {
  if (index < 0) return '';
  return str[index] + reverseStringRecursive(str, index - 1);
}

function isPalindrome(str) {
  const cleaned = str.toLowerCase().replace(/[^a-z0-9]/g, '');
  let left = 0, right = cleaned.length - 1;
  while (left < right) {
    if (cleaned[left] !== cleaned[right]) return false;
    left++;
    right--;
  }
  return true;
}

// Or simply:
function isPalindromeSimple(str) {
  const cleaned = str.toLowerCase().replace(/[^a-z0-9]/g, '');
  return cleaned === cleaned.split('').reverse().join('');
}

function countFrequencies(str) {
  const freq = {};
  for (const char of str) {
    freq[char] = (freq[char] || 0) + 1;
  }
  return freq;
}

// Using Map:
function countFrequenciesMap(str) {
  const freq = new Map();
  for (const char of str) {
    freq.set(char, (freq.get(char) || 0) + 1);
  }
  return freq;
}

function firstNonRepeating(str) {
  const freq = {};
  for (const char of str) {
    freq[char] = (freq[char] || 0) + 1;
  }
  for (const char of str) {
    if (freq[char] === 1) return char;
  }
  return null;
}

function areAnagrams(str1, str2) {
  const clean1 = str1.toLowerCase().replace(/\s/g, '').split('').sort().join('');
  const clean2 = str2.toLowerCase().replace(/\s/g, '').split('').sort().join('');
  return clean1 === clean2;
}

// Efficient approach:
function areAnagramsEfficient(str1, str2) {
  const clean1 = str1.toLowerCase().replace(/\s/g, '');
  const clean2 = str2.toLowerCase().replace(/\s/g, '');
  if (clean1.length !== clean2.length) return false;
  const freq = {};
  for (const char of clean1) freq[char] = (freq[char] || 0) + 1;
  for (const char of clean2) {
    if (!freq[char]) return false;
    freq[char]--;
  }
  return true;
}

function capitalizeBySplit(str) {
  return str.split(' ').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' ');
}

// Using regex:
function capitalizeByRegex(str) {
  return str.replace(/\b\w/g, char => char.toUpperCase());
}

// Manual approach:
function capitalizeManual(str) {
  let result = '';
  let capitalizeNext = true;
  for (const char of str) {
    if (char === ' ') {
      capitalizeNext = true;
      result += char;
    } else if (capitalizeNext) {
      result += char.toUpperCase();
      capitalizeNext = false;
    } else {
      result += char;
    }
  }
  return result;
}

function removeDuplicates(str) {
  return [...new Set(str)].join('');
}

// Preserve order:
function removeDuplicatesPreserve(str) {
  const seen = new Set();
  let result = '';
  for (const char of str) {
    if (!seen.has(char)) {
      seen.add(char);
      result += char;
    }
  }
  return result;
}

function compressString(str) {
  if (str.length <= 2) return str;
  let compressed = '';
  let count = 1;
  for (let i = 0; i < str.length; i++) {
    if (i + 1 >= str.length || str[i] !== str[i + 1]) {
      compressed += str[i] + count;
      count = 1;
    } else {
      count++;
    }
  }
  return compressed.length < str.length ? compressed : str;
}

function findLongestWord(sentence) {
  return sentence.split(' ').reduce((longest, word) => 
    word.length > longest.length ? word : longest
  );
}

// Using for loop:
function findLongestWordLoop(sentence) {
  const words = sentence.split(' ');
  let longest = '';
  for (const word of words) {
    if (word.length > longest.length) longest = word;
  }
  return longest;
}

function safeJsonParse(jsonString) {
  try {
    return JSON.parse(jsonString);
  } catch (e) {
