}

// With optional default value:
function safeJsonParseWithDefault(jsonString, defaultValue = null) {
  try {
    return JSON.parse(jsonString);
  } catch (e) {
    return defaultValue;
  }
}

function removeDuplicatesArray(arr) {
  return [...new Set(arr)];
}

// Preserve order with object:
function removeDuplicatesPreserveOrder(arr) {
  const seen = {};
  return arr.filter(item => {
    if (seen[item]) return false;
    seen[item] = true;
    return true;
  });
}

// For objects/complex types:
function removeDuplicatesObjects(arr, key) {
  const seen = new Set();
  return arr.filter(item => {
    if (seen.has(item[key])) return false;
    seen.add(item[key]);
    return true;
  });
}

function flattenArray(arr) {
  return arr.reduce((flat, item) => 
    flat.concat(Array.isArray(item) ? flattenArray(item) : item), []
  );
}

// Using flat():
function flattenArrayBuiltin(arr) {
  return arr.flat(Infinity);
}

// Iterative approach:
function flattenArrayIterative(arr) {
  const result = [];
  const stack = [...arr].reverse();
  while (stack.length) {
    const item = stack.pop();
    if (Array.isArray(item)) {
      stack.push(...item.reverse());
    } else {
      result.push(item);
    }
  }
  return result;
}

function findSecondLargest(arr) {
  if (arr.length < 2) return null;
  const sorted = [...new Set(arr)].sort((a, b) => b - a);
  return sorted.length < 2 ? null : sorted[1];
}

// Single pass O(n):
function findSecondLargestEfficient(arr) {
  if (arr.length < 2) return null;
  let largest = -Infinity, secondLargest = -Infinity;
  for (const num of arr) {
    if (num > largest) {
      secondLargest = largest;
      largest = num;
    } else if (num > secondLargest && num !== largest) {
      secondLargest = num;
    }
  }
  return secondLargest === -Infinity ? null : secondLargest;
}

function rotateArray(arr, k) {
  const n = arr.length;
  k = k % n; // Handle k > n
  return arr.slice(-k).concat(arr.slice(0, n - k));
}

// Reverse approach O(n) time, O(1) space:
function rotateArrayOptimal(arr, k) {
  k = k % arr.length;
  if (k === 0) return arr;

  function reverse(start, end) {
    while (start < end) {
      [arr[start], arr[end]] = [arr[end], arr[start]];
      start++;
      end--;
    }
  }

  reverse(0, arr.length - 1);
  reverse(0, k - 1);
  reverse(k, arr.length - 1);
  return arr;
}

function moveZeroesToEnd(arr) {
  const nonZeros = arr.filter(num => num !== 0);
  const zeros = arr.length - nonZeros.length;
  return [...nonZeros, ...Array(zeros).fill(0)];
}

// In-place approach:
function moveZeroesToEndInPlace(arr) {
  let insertPos = 0;
  for (let i = 0; i < arr.length; i++) {
    if (arr[i] !== 0) {
      arr[insertPos] = arr[i];
      insertPos++;
    }
  }
  while (insertPos < arr.length) {
    arr[insertPos] = 0;
    insertPos++;
  }
  return arr;
}

function findIntersection(arr1, arr2) {
  const set2 = new Set(arr2);
  return [...new Set(arr1.filter(item => set2.has(item)))];
}

// Alternative:
function findIntersectionAlt(arr1, arr2) {
  const map = {};
  for (const item of arr1) map[item] = true;
  return [...new Set(arr2.filter(item => map[item]))];
}

function findUnion(arr1, arr2) {
  return [...new Set([...arr1, ...arr2])];
}

// Alternative:
function findUnionAlt(arr1, arr2) {
  const result = [...arr1];
  const set = new Set(arr1);
  for (const item of arr2) {
    if (!set.has(item)) result.push(item);
  }
  return result;
}

function groupByKey(arr, key) {
  return arr.reduce((grouped, item) => {
    const groupKey = item[key];
    if (!grouped[groupKey]) grouped[groupKey] = [];
    grouped[groupKey].push(item);
    return grouped;
  }, {});
}

// Alternative with Map:
function groupByKeyMap(arr, key) {
  const grouped = new Map();
  arr.forEach(item => {
    const groupKey = item[key];
    if (!grouped.has(groupKey)) grouped.set(groupKey, []);
    grouped.get(groupKey).push(item);
  });
  return grouped;
}

function sortByTimestamp(arr, key = 'timestamp') {
  return arr.sort((a, b) => new Date(a[key]) - new Date(b[key]));
}

// Non-mutating:
function sortByTimestampImmutable(arr, key = 'timestamp') {
  return [...arr].sort((a, b) => new Date(a[key]) - new Date(b[key]));
}

// Descending:
function sortByTimestampDesc(arr, key = 'timestamp') {
  return [...arr].sort((a, b) => new Date(b[key]) - new Date(a[key]));
}

function deepClone(obj) {
  if (obj === null || typeof obj !== 'object') return obj;
  if (obj instanceof Date) return new Date(obj.getTime());
  if (obj instanceof Array) return obj.map(item => deepClone(item));
  if (obj instanceof Object) {
    const cloned = {};
    for (const key in obj) {
      if (obj.hasOwnProperty(key)) {
        cloned[key] = deepClone(obj[key]);
      }
    }
    return cloned;
  }
}

// Using JSON (works for serializable objects):
function deepCloneJSON(obj) {
  return JSON.parse(JSON.stringify(obj));
}

function deepEqual(obj1, obj2) {
  if (obj1 === obj2) return true;
  if (obj1 === null || obj2 === null) return false;
  if (typeof obj1 !== 'object' || typeof obj2 !== 'object') return false;

  const keys1 = Object.keys(obj1);
  const keys2 = Object.keys(obj2);

  if (keys1.length !== keys2.length) return false;

  for (const key of keys1) {
    if (!keys2.includes(key)) return false;
    if (!deepEqual(obj1[key], obj2[key])) return false;
  }
  return true;
}

function chunkArray(arr, k) {
  const chunks = [];
  for (let i = 0; i < arr.length; i += k) {
    chunks.push(arr.slice(i, i + k));
  }
  return chunks;
}

// Using reduce:
function chunkArrayReduce(arr, k) {
  return arr.reduce((chunks, item, i) => {
    if (i % k === 0) chunks.push([]);
    chunks[chunks.length - 1].push(item);
    return chunks;
  }, []);
}

function findDuplicates(arr) {
  const freq = {};
  arr.forEach(item => {
    freq[item] = (freq[item] || 0) + 1;
  });
  return Object.entries(freq).filter(([_, count]) => count > 1).reduce((dup, [item, count]) => {
    dup[item] = count;
    return dup;
  }, {});
}

// Using Map:
function findDuplicatesMap(arr) {
  const freq = new Map();
  arr.forEach(item => {
    freq.set(item, (freq.get(item) || 0) + 1);
  });
  return Object.fromEntries([...freq.entries()].filter(([_, count]) => count > 1));
}

function mergeSortedArrays(arr1, arr2) {
  return [...arr1, ...arr2].sort((a, b) => a - b);
}

// Two pointer approach O(n):
function mergeSortedArraysTwoPointer(arr1, arr2) {
  const result = [];
  let i = 0, j = 0;
  while (i < arr1.length && j < arr2.length) {
    if (arr1[i] <= arr2[j]) {
      result.push(arr1[i++]);
    } else {
      result.push(arr2[j++]);
    }
  }
  return [...result, ...arr1.slice(i), ...arr2.slice(j)];
}

function findMissing(arr) {
  const n = arr.length + 1;
  const expectedSum = (n * (n + 1)) / 2;
  const actualSum = arr.reduce((sum, num) => sum + num, 0);
  return expectedSum - actualSum;
}

// Using Set:
function findMissingSet(arr) {
  const set = new Set(arr);
  for (let i = 1; i <= arr.length + 1; i++) {
    if (!set.has(i)) return i;
  }
}

function twoSum(arr, target) {
  const seen = {};
  for (let i = 0; i < arr.length; i++) {
    const complement = target - arr[i];
    if (seen[complement] !== undefined) {
      return [seen[complement], i];
    }
    seen[arr[i]] = i;
  }
  return null;
}

// All pairs:
function twoSumAll(arr, target) {
  const seen = new Set();
  const pairs = [];
  for (const num of arr) {
    const complement = target - num;
    if (seen.has(complement)) {
      pairs.push([complement, num]);
    }
    seen.add(num);
  }
  return pairs;
}

function topKFrequent(arr, k) {
  const freq = {};
  for (const num of arr) {
    freq[num] = (freq[num] || 0) + 1;
  }
  return Object.entries(freq)
    .sort((a, b) => b[1] - a[1])
    .slice(0, k)
    .map(([num]) => parseInt(num));
}

// Using heap (min-heap):
function topKFrequentHeap(arr, k) {
  const freq = new Map();
  for (const num of arr) {
    freq.set(num, (freq.get(num) || 0) + 1);
  }
  const heap = [...freq.entries()].sort((a, b) => b[1] - a[1]);
  return heap.slice(0, k).map(([num]) => num);
}

function majorityElement(arr) {
  const freq = {};
  const target = Math.floor(arr.length / 2);
  for (const num of arr) {
    freq[num] = (freq[num] || 0) + 1;
    if (freq[num] > target) return num;
  }
  return null;
}

// Boyer-Moore voting algorithm O(1) space:
function majorityElementOptimal(arr) {
  let candidate = null, count = 0;
  for (const num of arr) {
    if (count === 0) candidate = num;
    count += (num === candidate) ? 1 : -1;
  }
  return candidate;
}

function countWords(sentence) {
  return sentence.toLowerCase()
    .split(/\s+/)
    .reduce((freq, word) => {
      const clean = word.replace(/[^a-z0-9]/g, '');
      if (clean) freq[clean] = (freq[clean] || 0) + 1;
      return freq;
    }, {});
}

// Using Map:
function countWordsMap(sentence) {
  const freq = new Map();
  sentence.toLowerCase().split(/\s+/).forEach(word => {
    const clean = word.replace(/[^a-z0-9]/g, '');
    if (clean) freq.set(clean, (freq.get(clean) || 0) + 1);
  });
  return freq;
}

function findAllPairs(arr, target) {
  const seen = new Set();
  const pairs = new Set();
  for (const num of arr) {
    const complement = target - num;
    if (seen.has(complement)) {
      const pair = [Math.min(num, complement), Math.max(num, complement)];
      pairs.add(JSON.stringify(pair));
    }
    seen.add(num);
  }
  return Array.from(pairs).map(p => JSON.parse(p));
}

function threeSum(arr) {
  const sorted = arr.sort((a, b) => a - b);
  const triplets = [];
  for (let i = 0; i < sorted.length - 2; i++) {
    if (i > 0 && sorted[i] === sorted[i - 1]) continue; // skip duplicates
    let left = i + 1, right = sorted.length - 1;
    while (left < right) {
      const sum = sorted[i] + sorted[left] + sorted[right];
      if (sum === 0) {
        triplets.push([sorted[i], sorted[left], sorted[right]]);
        while (left < right && sorted[left] === sorted[left + 1]) left++;
        while (left < right && sorted[right] === sorted[right - 1]) right--;
        left++;
        right--;
      } else if (sum < 0) {
        left++;
      } else {
        right--;
      }
    }
  }
  return triplets;
}

function hasDuplicatesWithinK(arr, k) {
  const window = new Set();
  for (let i = 0; i < arr.length; i++) {
    if (window.has(arr[i])) return true;
    window.add(arr[i]);
    if (window.size > k) {
      window.delete(arr[i - k]);
    }
  }
  return false;
}

function firstRepeated(arr) {
  const seen = new Set();
  for (const num of arr) {
    if (seen.has(num)) return num;
    seen.add(num);
  }
  return null;
}

function flattenObject(obj, parent = '', result = {}) {
  for (const key in obj) {
    if (obj.hasOwnProperty(key)) {
      const newKey = parent ? `${parent}.${key}` : key;
      if (typeof obj[key] === 'object' && obj[key] !== null && !Array.isArray(obj[key])) {
        flattenObject(obj[key], newKey, result);
      } else {
        result[newKey] = obj[key];
      }
    }
  }
  return result;
}

function factorial(n) {
  if (n < 0) return null;
  if (n === 0 || n === 1) return 1;
  return n * factorial(n - 1);
}

// With memoization:
function factorialMemo() {
  const memo = {};
  return function calculate(n) {
    if (n in memo) return memo[n];
    if (n === 0 || n === 1) return 1;
    memo[n] = n * calculate(n - 1);
    return memo[n];
  };
}

function fibonacci(n) {
  if (n <= 0) return [];
  const fib = [0, 1];
  for (let i = 2; i < n; i++) {
    fib[i] = fib[i - 1] + fib[i - 2];
  }
  return fib.slice(0, n);
}

// Pure recursive:
function fibonacciRecursive(n) {
  if (n <= 0) return [];
  if (n === 1) return [0];
  const prev = fibonacciRecursive(n - 1);
  return [...prev, prev[prev.length - 1] + (prev[prev.length - 2] || 0)];
}

function traverseTree(node, callback) {
  callback(node);
  if (node.children && Array.isArray(node.children)) {
    node.children.forEach(child => traverseTree(child, callback));
  }
}

// Collect all values:
function collectTreeValues(node) {
  let values = [node.value];
  if (node.children && Array.isArray(node.children)) {
    node.children.forEach(child => {
      values = values.concat(collectTreeValues(child));
    });
  }
  return values;
}

// Find node:
function findInTree(node, predicate) {
  if (predicate(node)) return node;
  if (node.children && Array.isArray(node.children)) {
    for (const child of node.children) {
      const result = findInTree(child, predicate);
      if (result) return result;
    }
  }
  return null;
}

function dfs(graph, start, visited = new Set()) {
  visited.add(start);
  const result = [start];
  for (const neighbor of graph[start] || []) {
    if (!visited.has(neighbor)) {
      result.push(...dfs(graph, neighbor, visited));
    }
  }
  return result;
}

// Iterative:
function dfsIterative(graph, start) {
  const visited = new Set();
  const stack = [start];
  const result = [];
  while (stack.length > 0) {
    const node = stack.pop();
    if (!visited.has(node)) {
      visited.add(node);
      result.push(node);
      for (const neighbor of (graph[node] || []).reverse()) {
        if (!visited.has(neighbor)) stack.push(neighbor);
      }
    }
  }
  return result;
}

function bfs(graph, start) {
  const visited = new Set([start]);
  const queue = [start];
  const result = [start];

  while (queue.length > 0) {
    const node = queue.shift();
    for (const neighbor of graph[node] || []) {
      if (!visited.has(neighbor)) {
        visited.add(neighbor);
        queue.push(neighbor);
        result.push(neighbor);
      }
    }
  }
  return result;
}

function hasCycle(graph) {
  const visited = new Set();
  const recStack = new Set();

  function dfs(node) {
    visited.add(node);
    recStack.add(node);

    for (const neighbor of graph[node] || []) {
      if (!visited.has(neighbor)) {
        if (dfs(neighbor)) return true;
      } else if (recStack.has(neighbor)) {
        return true;
      }
    }
    recStack.delete(node);
    return false;
  }

  for (const node in graph) {
    if (!visited.has(node) && dfs(node)) return true;
  }
  return false;
}

function delay(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

// With value:
function delayWithValue(ms, value) {
  return new Promise(resolve => setTimeout(() => resolve(value), ms));
}

async function sequentialAsync(fn1, fn2, fn3) {
  const result1 = await fn1();
  const result2 = await fn2();
  const result3 = await fn3();
  return { result1, result2, result3 };
}

// Using reduce:
async function runSequential(fns) {
  return fns.reduce(async (prev, fn) => {
    await prev;
    return fn();
  }, Promise.resolve());
}

async function parallelAsync(fn1, fn2, fn3) {
  return Promise.all([fn1(), fn2(), fn3()]);
}

// Collect with labels:
async function parallelWithLabels(tasks) {
  const results = await Promise.all(tasks.map(t => t.fn()));
  return tasks.reduce((acc, task, i) => {
    acc[task.label] = results[i];
    return acc;
  }, {});
}

async function limitConcurrency(tasks, k) {
  const results = [];
  for (let i = 0; i < tasks.length; i += k) {
    const batch = tasks.slice(i, i + k);
    const batchResults = await Promise.all(batch.map(t => t()));
    results.push(...batchResults);
  }
  return results;
}

// More elegant:
async function concurrencyQueue(tasks, limit) {
  const results = [];
  const executing = [];

  for (const [index, task] of tasks.entries()) {
    const p = Promise.resolve().then(() => task()).then(result => {
      results[index] = result;
    });

    results[index] = p;

    if (tasks.length >= limit) {
      executing.push(p);
      p.then(() => executing.splice(executing.indexOf(p), 1));
      if (executing.length >= limit) {
        await Promise.race(executing);
      }
    }
  }

  await Promise.all(results);
  return results;
}

async function retry(fn, maxRetries = 3) {
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error) {
      if (i === maxRetries - 1) throw error;
    }
  }
}

// With logging:
async function retryWithLog(fn, maxRetries = 3) {
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error) {
      console.log(`Attempt ${i + 1} failed:`, error.message);
      if (i === maxRetries - 1) throw error;
    }
  }
}

async function retryWithBackoff(fn, maxRetries = 3, baseDelay = 1000) {
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error) {
      if (i === maxRetries - 1) throw error;
      const delay = baseDelay * Math.pow(2, i);
      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }
}

function withTimeout(promise, ms) {
  return Promise.race([
    promise,
    new Promise((_, reject) => 
      setTimeout(() => reject(new Error(`Timeout after ${ms}ms`)), ms)
    )
  ]);
}

function promiseAll(promises) {
  return new Promise((resolve, reject) => {
    if (!Array.isArray(promises) || promises.length === 0) {
      resolve([]);
      return;
    }

    const results = new Array(promises.length);
    let fulfilled = 0;

    promises.forEach((promise, index) => {
      Promise.resolve(promise)
        .then(value => {
          results[index] = value;
          fulfilled++;
          if (fulfilled === promises.length) resolve(results);
        })
        .catch(reject);
    });
  });
}

function promiseRace(promises) {
  return new Promise((resolve, reject) => {
    if (!Array.isArray(promises) || promises.length === 0) {
      return;
    }

    for (const promise of promises) {
