// With this binding:
function debounceThis(fn, delay) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => fn.call(this, ...args), delay);
  };
}

function throttle(fn, delay) {
  let lastCall = 0;
  return function(...args) {
    const now = Date.now();
    if (now - lastCall >= delay) {
      lastCall = now;
      fn(...args);
    }
  };
}

// Leading and trailing options:
function throttleAdvanced(fn, delay, { leading = true, trailing = true } = {}) {
  let timeoutId, lastCall = 0;
  return function(...args) {
    const now = Date.now();
    if (!lastCall && !leading) lastCall = now;
    const remaining = delay - (now - lastCall);
    if (remaining <= 0) {
      clearTimeout(timeoutId);
      fn(...args);
      lastCall = now;
    } else if (trailing) {
      clearTimeout(timeoutId);
      timeoutId = setTimeout(() => fn(...args), remaining);
    }
  };
}

function once(fn) {
  let called = false;
  let result;
  return function(...args) {
    if (!called) {
      called = true;
      result = fn(...args);
    }
    return result;
  };
}

function memoize(fn) {
  const cache = {};
  return function(...args) {
    const key = JSON.stringify(args);
    if (key in cache) return cache[key];
    const result = fn(...args);
    cache[key] = result;
    return result;
  };
}

