async function processCSVInBackground(filePath, jobId) {
  const results = [];
  fs.createReadStream(filePath)
    .pipe(csv())
    .on('data', (data) => results.push(data))
    .on('end', async () => {
      await db.records.insertMany(results);
      jobs[jobId] = { status: 'completed', recordsImported: results.length };
      fs.unlinkSync(filePath);
    });
}

const schedule = require('node-schedule');
const tasks = new Map();

function scheduleTask(jobId, executeAt, fn) {
  const job = schedule.scheduleJob(executeAt, fn);
  tasks.set(jobId, job);
  return jobId;
}

app.post('/schedule', (req, res) => {
  const { executeAt, action, params } = req.body;
  const jobId = Date.now().toString();

  scheduleTask(jobId, new Date(executeAt), () => {
    performAction(action, params);
  });

  res.json({ jobId, status: 'scheduled' });
});

