async function getTopScores(limit = 10) {
  const scores = await client.zrevrange('leaderboard', 0, limit - 1, 'WITHSCORES');
  const result = [];
  for (let i = 0; i < scores.length; i += 2) {
    result.push({ userId: scores[i], score: parseInt(scores[i + 1]) });
